mapper.select:


    and rlr.limit_rule_id = #{limitRuleId}
    and rlr.limit_rule_dimension =
        #{limitRuleDimension}

    and rlr.limit_rule_target_id = #{limitRuleTargetId}
    and rlr.limit_rule_type = #{limitRuleType}
    and rlr.flow_control_mode = #{flowControlMode}

    and rlr.flow_control_effect =
        #{flowControlEffect}

    and rlr.flow_rule_type = #{flowRuleType}
    and rlr.flow_threshold = #{flowThreshold}
    and rlr.circuit_strategy = #{circuitStrategy}
    and rlr.circuit_threshold = #{circuitThreshold}
    and rlr.circuit_grade = #{circuitGrade}
    and rlr.circuit_window = #{circuitWindow}
    and rlr.circuit_timeout = #{circuitTimeout}
    and rlr.limit_rule_status = #{limitRuleStatus}

    and rlr.limit_rule_remark = #{limitRuleRemark}

    and rlr.del_flag = #{delFlag}
    and rlr.user_id = #{userId}
    and rlr.create_by like concat('%',
        #{createBy}, '%')

    and rlr.create_time between #{beginCreateTime} and
        #{endCreateTime}

    and rlr.update_by like concat('%',
        #{updateBy}, '%')

    and rlr.update_time between #{beginUpdateTime} and
        #{endUpdateTime}


order by STR_TO_DATE(rlr.create_time, "%Y-%m-%d %H:%i:%s") desc
